// Build the list of club ids to scrape, one item per club. The 'Fire workers' HTTP
// node paces them via its native Batching option (no splitInBatches / Wait-node resume
// chain — that design hung and orphaned executions at scale).
const body=($('Webhook').first().json.body)||{};
const force = body.force === true;
const limit = body.limit ? Number(body.limit) : 0;
let ids=[];
if (Array.isArray(body.ids) && body.ids.length){
  ids = body.ids.filter(Boolean);
} else {
  // no ids: every usable, not-yet-site-scraped club. 'already scraped' = scrape_note set
  // (the worker's own marker), NOT status (also set by directory extraction). C excluded.
  const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
  const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
  let flt='((website_status="live" && (website_confidence="A" || website_confidence="B")) || detail_url!="")';
  if (!force) flt+=' && scrape_note=""';
  let page=1;
  while(true){ const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:flt,perPage:500,page,fields:'id'},headers:pbH,json:true}); ids=ids.concat((r.items||[]).map(x=>x.id)); if(page>=(r.totalPages||1))break; page++; }
}
if(limit>0) ids=ids.slice(0,limit);
if(!ids.length) return [{json:{__skip:true}}];
return ids.map(id=>({json:{id,force}}));
